using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // In .NET 9, ZipArchiveEntry now respects the UTF-8 flag and always
        // writes UTF-8 names. The legacy Java consumer expects Shift-JIS, so
        // we must explicitly specify the encoding to suppress the UTF-8 flag.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift_JIS");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

// In .NET 9, [FromKeyedServices("cache")] no longer falls back to
// a non-keyed registration — it throws InvalidOperationException.
// Register as a keyed service to match the controller attribute.
services.AddKeyedSingleton<ICache, RedisCache>("cache");

